class Solution(object):
    def closestNodes(self, root, queries):
        values = []
        def inorder(node):
            if not node:
                return
            inorder(node.left)
            values.append(node.val)
            inorder(node.right)
        inorder(root)
        result = []
        for q in queries:
            left, right = -1, -1
            lo, hi = 0, len(values) - 1
            while lo <= hi:
                mid = (lo + hi) // 2
                if values[mid] <= q:
                    left = values[mid]
                    lo = mid + 1
                else:
                    hi = mid - 1
            lo, hi = 0, len(values) - 1
            while lo <= hi:
                mid = (lo + hi) // 2
                if values[mid] >= q:
                    right = values[mid]
                    hi = mid - 1
                else:
                    lo = mid + 1
            result.append([left, right])
        return result
